import{_ as i,o as n,c as a,ag as t}from"./chunks/framework.ByAj6Cie.js";const d=JSON.parse('{"title":"Alignment","description":"","frontmatter":{},"headers":[],"relativePath":"es/industrial-practices/installation-mounting/alignment.md","filePath":"es/industrial-practices/installation-mounting/alignment.md"}'),l={name:"es/industrial-practices/installation-mounting/alignment.md"};function o(s,e,r,c,m,p){return n(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="alignment" tabindex="-1">Alignment <a class="header-anchor" href="#alignment" aria-label="Permalink to &quot;Alignment&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Alignment is the process of positioning connected components so that their axes, centers, or reference points are correctly matched.</p><p>It is especially critical in rotating equipment where shafts must be aligned to transmit power efficiently and avoid mechanical stress.</p><p>Proper alignment ensures smooth operation and reduces wear.</p><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>The purpose of alignment is to ensure that connected components operate without introducing unnecessary forces or vibration.</p><p>This helps to:</p><ul><li>Reduce mechanical stress on components</li><li>Extend equipment lifespan</li><li>Improve efficiency and performance</li><li>Prevent premature failures</li></ul><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>Alignment involves adjusting the position of equipment so that connected parts are correctly oriented.</p><p>In rotating systems, this typically means aligning shafts in terms of:</p><ul><li>Angular alignment, where the axes are parallel</li><li>Offset alignment, where the centers are on the same line</li></ul><p>Adjustments are made by:</p><ul><li>Shimming or adjusting mounting surfaces</li><li>Moving equipment horizontally or vertically</li><li>Using measurement tools such as dial indicators or laser alignment systems</li></ul><p>Alignment must be checked under real installation conditions.</p><h2 id="applications" tabindex="-1">Applications <a class="header-anchor" href="#applications" aria-label="Permalink to &quot;Applications&quot;">​</a></h2><p>Alignment is critical in:</p><ul><li>Motor and pump installations</li><li>Gearboxes and drive systems</li><li>Coupled rotating equipment</li><li>Conveyor systems</li><li>Any system with connected rotating parts</li></ul><h2 id="key-considerations" tabindex="-1">Key Considerations <a class="header-anchor" href="#key-considerations" aria-label="Permalink to &quot;Key Considerations&quot;">​</a></h2><ul><li>Alignment tolerances depend on equipment type and speed</li><li>Thermal expansion can affect alignment during operation</li><li>Foundation stability influences alignment over time</li><li>Misalignment increases vibration and energy loss</li><li>Regular verification may be required in critical systems</li></ul><h2 id="practical-notes" tabindex="-1">Practical Notes <a class="header-anchor" href="#practical-notes" aria-label="Permalink to &quot;Practical Notes&quot;">​</a></h2><ul><li>Misalignment is a common cause of bearing and coupling failures</li><li>Precision alignment reduces maintenance frequency</li><li>Recheck alignment after tightening and during commissioning</li><li>Soft foot conditions can affect alignment accuracy</li><li>Always align under conditions close to actual operation</li></ul>',23)])])}const h=i(l,[["render",o]]);export{d as __pageData,h as default};
